// Notification Log
export type {
  NotificationLog,
  NotificationHistoryQuery,
  DeliveryStatus,
} from './models/notification-log.js';
export { NotificationLogRepository } from './repositories/notification-log.repository.js';
export { NotificationHistoryService } from './services/notification-history.service.js';

// User Preferences
export type {
  UserPreferences,
  EmailPreferences,
  EmailFrequency,
  UpdateEmailPreferencesInput,
  SmsPreferences,
  UpdateSmsPreferencesInput,
  WebhookPreferences,
  UpdateWebhookPreferencesInput,
} from './models/user-preferences.js';
export {
  getDefaultEmailPreferences,
  getDefaultSmsPreferences,
  getDefaultWebhookPreferences,
  ALL_NOTIFICATION_CATEGORIES,
} from './models/user-preferences.js';
export { PreferencesRepository } from './repositories/preferences.repository.js';
export { PreferencesService } from './services/preferences.service.js';

// Adapters
export type { NotificationAdapter } from './adapters/notification.adapter.js';
export { EmailNotificationAdapter } from './adapters/email.adapter.js';
export type { EmailConfig } from './adapters/email.adapter.js';
export { SmsNotificationAdapter } from './adapters/sms.adapter.js';
export type { SmsConfig } from './adapters/sms.adapter.js';
export { WebhookNotificationAdapter } from './adapters/webhook.adapter.js';
export type { WebhookConfig } from './adapters/webhook.adapter.js';

// Callback Registry
export { CallbackRegistry } from './utils/callback-registry.js';

// Config
export { createConfig, defaultConfig } from './config/app.config.js';
export type { AppConfig } from './config/app.config.js';

